package main

import (
	"strings"
)

// ParseGoMod extracts the module name from a go.mod file's contents.
func ParseGoMod(contents string) string {
	lines := strings.[[SLOT split_fn]](contents, "\n")
	for _, line := range lines {
		line = strings.[[SLOT trim_fn]](line)
		if line == "" {
			continue
		}
		if strings.[[SLOT prefix_check]](line, [[SLOT prefix_str]]) {
			return strings.TrimPrefix(line, "module ")
		}
	}
	return ""
}

func main() {
	gomod := "module hello_world\n\ngo 1.20\n"
	result := ParseGoMod(gomod)
	println(result)
}
